'use client';

import * as React from 'react';
import { cva, type VariantProps } from 'class-variance-authority';
import { cn } from '@/lib/utils';

const buttonVariants = cva(
  [
    'inline-flex items-center justify-center gap-2',
    'whitespace-nowrap rounded-lg text-sm font-medium',
    'transition-all duration-200 ease-in-out',
    'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-offset-2',
    'disabled:pointer-events-none disabled:opacity-50',
    'active:scale-[0.98]',
  ],
  {
    variants: {
      variant: {
        default: [
          'bg-stone-800 text-stone-50',
          'hover:bg-stone-700',
          'focus-visible:ring-stone-500',
          'shadow-sm hover:shadow-md',
        ],
        primary: [
          'bg-amber-700 text-white',
          'hover:bg-amber-800',
          'focus-visible:ring-amber-500',
          'shadow-sm hover:shadow-md',
        ],
        secondary: [
          'bg-stone-100 text-stone-900',
          'hover:bg-stone-200',
          'focus-visible:ring-stone-400',
        ],
        outline: [
          'border-2 border-stone-300 bg-transparent',
          'text-stone-700',
          'hover:border-stone-400 hover:bg-stone-50',
          'focus-visible:ring-stone-400',
        ],
        ghost: [
          'bg-transparent text-stone-700',
          'hover:bg-stone-100',
          'focus-visible:ring-stone-400',
        ],
        destructive: [
          'bg-red-600 text-white',
          'hover:bg-red-700',
          'focus-visible:ring-red-500',
          'shadow-sm hover:shadow-md',
        ],
        link: [
          'bg-transparent text-amber-700 underline-offset-4',
          'hover:underline',
          'focus-visible:ring-amber-500',
        ],
        glass: [
          'bg-white/80 backdrop-blur-md text-stone-800',
          'border border-white/20',
          'hover:bg-white/90',
          'shadow-lg hover:shadow-xl',
          'focus-visible:ring-stone-400',
        ],
        gradient: [
          'bg-gradient-to-r from-amber-700 to-orange-600 text-white',
          'hover:from-amber-800 hover:to-orange-700',
          'shadow-md hover:shadow-lg',
          'focus-visible:ring-orange-500',
        ],
        soft: [
          'bg-amber-100 text-amber-900',
          'hover:bg-amber-200',
          'focus-visible:ring-amber-400',
        ],
      },
      size: {
        xs: 'h-7 px-2.5 text-xs gap-1.5',
        sm: 'h-8 px-3 text-sm gap-1.5',
        md: 'h-10 px-4 text-sm gap-2',
        lg: 'h-12 px-6 text-base gap-2.5',
        xl: 'h-14 px-8 text-lg gap-3',
        icon: 'h-10 w-10 p-2',
      },
      fullWidth: {
        true: 'w-full',
        false: '',
      },
      loading: {
        true: 'cursor-wait opacity-70',
        false: '',
      },
      rounded: {
        none: 'rounded-none',
        sm: 'rounded-sm',
        md: 'rounded-md',
        lg: 'rounded-lg',
        xl: 'rounded-xl',
        full: 'rounded-full',
      },
    },
    defaultVariants: {
      variant: 'default',
      size: 'md',
      fullWidth: false,
      loading: false,
      rounded: 'lg',
    },
  }
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  loading?: boolean;
  loadingText?: string;
  asChild?: boolean;
  leftIcon?: React.ReactNode;
  rightIcon?: React.ReactNode;
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  (
    {
      className,
      variant,
      size,
      fullWidth,
      loading,
      loadingText,
      rounded,
      children,
      disabled,
      leftIcon,
      rightIcon,
      ...props
    },
    ref
  ) => {
    const isDisabled = disabled || loading;

    return (
      <button
        className={cn(
          buttonVariants({
            variant,
            size,
            fullWidth,
            loading,
            rounded,
          }),
          className
        )}
        ref={ref}
        disabled={isDisabled}
        aria-busy={loading}
        {...props}
      >
        {loading ? (
          <>
            <svg
              className="animate-spin shrink-0"
              xmlns="http://www.w3.org/2000/svg"
              width={size === 'xs' || size === 'sm' ? 14 : size === 'lg' || size === 'xl' ? 20 : 16}
              height={size === 'xs' || size === 'sm' ? 14 : size === 'lg' || size === 'xl' ? 20 : 16}
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            >
              <path d="M21 12a9 9 0 1 1-6.219-8.56" />
            </svg>
            <span>{loadingText || children}</span>
          </>
        ) : (
          <>
            {leftIcon && <span>{leftIcon}</span>}
            {children}
            {rightIcon && <span>{rightIcon}</span>}
          </>
        )}
      </button>
    );
  }
);

Button.displayName = 'Button';

export { Button, buttonVariants };

import { clsx, type ClassValue } from 'clsx';
import { twMerge } from 'tailwind-merge';

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

'use client';

import * as React from 'react';
import { cva, cn } from '@brownie-ui/core';

const gaugeVariants = cva(
  'relative inline-flex flex-col items-center justify-center'
);

function valueToAngle(value: number, min: number, max: number): number {
  const clampedValue = Math.max(min, Math.min(max, value));
  return ((clampedValue - min) / (max - min)) * 180;
}

function getScoreColor(value: number, min: number, max: number): string {
  const percentage = (value - min) / (max - min);
  if (percentage <= 0.25) return '#ef4444';
  if (percentage <= 0.5) return '#f97316';
  if (percentage <= 0.75) return '#eab308';
  return '#22c55e';
}

function getScoreLabel(value: number, min: number, max: number): string {
  const percentage = (value - min) / (max - min);
  if (percentage <= 0.25) return 'Poor';
  if (percentage <= 0.5) return 'Fair';
  if (percentage <= 0.75) return 'Good';
  if (percentage <= 0.9) return 'Very Good';
  return 'Excellent';
}

interface GaugeSegment {
  start: number;
  end: number;
  color: string;
}

export interface GaugeProps extends React.HTMLAttributes<HTMLDivElement> {
  value: number;
  min?: number;
  max?: number;
  title?: string;
  label?: string;
  showAutoLabel?: boolean;
  segments?: GaugeSegment[];
  size?: number;
  animationDuration?: number;
  formatValue?: (value: number) => string;
  variant?: 'default' | 'minimal' | 'compact';
}

const Gauge = React.forwardRef<HTMLDivElement, GaugeProps>(
  (
    {
      value,
      min = 300,
      max = 900,
      title = 'My Credit Score',
      label,
      showAutoLabel = true,
      segments,
      size = 320,
      animationDuration = 1500,
      formatValue = (v) => v.toString(),
      variant = 'default',
      className,
      ...props
    },
    ref
  ) => {
    const [displayValue, setDisplayValue] = React.useState(min);
    const [indicatorAngle, setIndicatorAngle] = React.useState(0);

    React.useEffect(() => {
      const startTime = Date.now();
      const startValue = displayValue;
      const targetAngle = valueToAngle(value, min, max);

      const animate = () => {
        const elapsed = Date.now() - startTime;
        const progress = Math.min(elapsed / animationDuration, 1);
        const easeOut = 1 - Math.pow(1 - progress, 3);

        const currentValue = Math.round(startValue + (value - startValue) * easeOut);
        const currentAngle = targetAngle * easeOut;

        setDisplayValue(currentValue);
        setIndicatorAngle(currentAngle);

        if (progress < 1) {
          requestAnimationFrame(animate);
        }
      };

      requestAnimationFrame(animate);
    }, [value, min, max, animationDuration]);

    const defaultSegments: GaugeSegment[] = [
      { start: 0, end: 0.22, color: '#ef4444' },
      { start: 0.26, end: 0.48, color: '#f59e0b' },
      { start: 0.52, end: 0.74, color: '#fbbf24' },
      { start: 0.78, end: 1, color: '#22c55e' },
    ];

    const activeSegments = segments || defaultSegments;
    const currentColor = getScoreColor(value, min, max);
    const rating = getScoreLabel(value, min, max);

    const strokeWidth = variant === 'compact' ? 6 : 8;
    const gapSize = 8;
    const radius = (size - strokeWidth * 2) / 2;
    const centerX = size / 2;
    const centerY = size / 2 + 40;

    const describeArc = (startAngle: number, endAngle: number, innerRadius: number) => {
      const polarToCartesian = (cx: number, cy: number, r: number, angle: number) => {
        const rad = ((angle - 180) * Math.PI) / 180;
        return { x: cx + r * Math.cos(rad), y: cy + r * Math.sin(rad) };
      };

      const start = polarToCartesian(centerX, centerY, innerRadius, endAngle);
      const end = polarToCartesian(centerX, centerY, innerRadius, startAngle);
      const largeArcFlag = endAngle - startAngle <= 180 ? '0' : '1';

      return [`M`, start.x, start.y, 'A', innerRadius, innerRadius, 0, largeArcFlag, 0, end.x, end.y].join(' ');
    };

    const polarToCartesian = (centerX: number, centerY: number, radius: number, angleInDegrees: number) => {
      const angleInRadians = ((angleInDegrees - 180) * Math.PI) / 180;
      return {
        x: centerX + radius * Math.cos(angleInRadians),
        y: centerY + radius * Math.sin(angleInRadians),
      };
    };

    const indicatorPos = polarToCartesian(centerX, centerY, radius, indicatorAngle);

    return (
      <div ref={ref} className={cn(gaugeVariants({}), className)} style={{ width: size }} {...props}>
        {title && variant !== 'minimal' && (
          <h3 className="text-lg font-semibold text-gray-800 dark:text-gray-100 mb-4">{title}</h3>
        )}
        <div className="relative" style={{ width: size, height: size / 2 + 80 }}>
          <svg width={size} height={size / 2 + 80} viewBox={`0 0 ${size} ${size / 2 + 80}`} className="overflow-visible">
            {activeSegments.map((segment, index) => {
              const startAngle = segment.start * 180;
              const endAngle = segment.end * 180;
              const gapAngle = (gapSize / (Math.PI * radius)) * 180;
              const adjustedStart = startAngle + gapAngle / 2;
              const adjustedEnd = endAngle - gapAngle / 2;
              const segmentPath = describeArc(adjustedStart, adjustedEnd, radius);
              return (
                <path key={index} d={segmentPath} fill="none" stroke={segment.color} strokeWidth={strokeWidth} strokeLinecap="round" />
              );
            })}
            {variant !== 'minimal' && Array.from({ length: 31 }).map((_, i) => {
              const angle = (i / 30) * 180;
              const dotRadius = radius - strokeWidth - 8;
              const dotPos = polarToCartesian(centerX, centerY, dotRadius, angle);
              return (
                <circle key={`dot-${i}`} cx={dotPos.x} cy={dotPos.y} r={2} fill="#d1d5db" opacity={0.6} />
              );
            })}
            <g style={{ transition: 'all 0.1s ease-out' }}>
              <circle cx={indicatorPos.x} cy={indicatorPos.y} r={10} fill="white" stroke="#10b981" strokeWidth={2} />
              <circle cx={indicatorPos.x} cy={indicatorPos.y} r={4} fill="#10b981" />
            </g>
          </svg>
          <div className="absolute left-1/2 text-center" style={{ bottom: '35px', transform: 'translateX(-50%)' }}>
            <span className={cn('font-bold tabular-nums text-gray-800 dark:text-gray-900 block leading-none', variant === 'compact' ? 'text-4xl' : 'text-6xl')}>
              {formatValue(displayValue)}
            </span>
          </div>
        </div>
        {variant !== 'minimal' && (
          <div className="mt-2 text-center">
            {showAutoLabel && (
              <p className="text-sm font-medium text-gray-700 dark:text-gray-300">
                Your Credit Score is <span className="font-semibold" style={{ color: currentColor }}>{rating}</span>
              </p>
            )}
            {label && <p className="text-sm font-medium text-gray-700 dark:text-gray-300">{label}</p>}
          </div>
        )}
      </div>
    );
  }
);

Gauge.displayName = 'Gauge';
export { Gauge, gaugeVariants };
export type { GaugeSegment };

'use client';

import * as React from 'react';
import { cva, cn } from '@brownie-ui/core';

const cardVariants = cva(
  'relative overflow-hidden bg-white rounded-[32px] shadow-xl',
  {
    variants: {
      size: {
        sm: 'w-64',
        md: 'w-80',
        lg: 'w-96',
        full: 'w-full',
      },
    },
    defaultVariants: {
      size: 'md',
    },
  }
);

export interface CardProps extends React.HTMLAttributes<HTMLDivElement> {
  image?: string;
  imageAlt?: string;
  title?: string;
  subtitle?: string;
  isConnecting?: boolean;
  avatar?: string;
  username?: string;
  timestamp?: string;
  actionText?: string;
  onAction?: () => void;
  size?: 'sm' | 'md' | 'lg' | 'full';
  footer?: React.ReactNode;
  aspectRatio?: string;
}

const Card = React.forwardRef<HTMLDivElement, CardProps>(
  (
    {
      image,
      imageAlt,
      title,
      subtitle,
      isConnecting = false,
      avatar,
      username,
      timestamp,
      actionText = 'More Info',
      onAction,
      size = 'md',
      footer,
      aspectRatio = '4/5',
      className,
      children,
      ...props
    },
    ref
  ) => {
    return (
      <div ref={ref} className={cn(cardVariants({ size }), className)} {...props}>
        {image && (
          <div className="relative w-full overflow-hidden" style={{ aspectRatio }}>
            <img src={image} alt={imageAlt || title || 'Card image'} className="w-full h-full object-cover" />
            <div className="absolute inset-0 bg-gradient-to-b from-black/40 via-transparent to-black/20" />
            {(title || subtitle) && (
              <div className="absolute top-4 left-4 right-4 text-white">
                {title && <h3 className="text-xl font-semibold tracking-wide">{title}</h3>}
                {subtitle && (
                  <div className="flex items-center gap-1.5 mt-1">
                    {isConnecting && (
                      <svg className="animate-spin h-3.5 w-3.5 text-white/80" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                      </svg>
                    )}
                    <span className="text-sm text-white/80 font-medium">{subtitle}</span>
                  </div>
                )}
              </div>
            )}
            {children && <div className="absolute inset-0">{children}</div>}
          </div>
        )}
        {footer ? (
          <div className="p-4">{footer}</div>
        ) : (
          (avatar || username || onAction) && (
            <div className="absolute bottom-4 left-4 right-4 flex items-center justify-between">
              {(avatar || username || timestamp) && (
                <div className="flex items-center gap-3">
                  {avatar && <img src={avatar} alt={username || 'User'} className="w-10 h-10 rounded-full object-cover border-2 border-white/50" />}
                  {(username || timestamp) && (
                    <div className="flex flex-col">
                      {username && <span className="text-sm font-semibold text-white drop-shadow-md">{username}</span>}
                      {timestamp && <span className="text-xs text-white/70 drop-shadow-md">{timestamp}</span>}
                    </div>
                  )}
                </div>
              )}
              {onAction && (
                <button onClick={onAction} className={cn('flex items-center gap-1.5 px-4 py-2 bg-white dark:bg-gray-800 text-gray-900 dark:text-white text-sm font-medium rounded-full shadow-md hover:bg-gray-50 dark:hover:bg-gray-700 active:scale-95 transition-all duration-200')}>
                  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="12" y1="5" x2="12" y2="19" /><line x1="5" y1="12" x2="19" y2="12" /></svg>
                  {actionText}
                </button>
              )}
            </div>
          )
        )}
      </div>
    );
  }
);

Card.displayName = 'Card';
export { Card, cardVariants };
export type { CardProps };
